    @classmethod
    def get_operations(
        cls, info: ResolveInfo, operations: list[ProductAttributeAssignInput]
    ):
        """Resolve all passed global ids into integer PKs of the Attribute type."""
        product_attrs_pks = []
        variant_attrs_pks = []
